\begin{align*} \frac{\sin \angle B}{24} &= \frac{\sin \angle C}{28}\\\\ \frac{\sin (180- \angle A- \angle B)}{24} &= \frac{\sin \angle A}{21}\\\\ \frac{\sin (\angle A + \angle B)}{24} &= \frac{\sin \angle A}{21}\\\\ \frac{\sin \angle A \cos \angle B + \cos \angle A \sin \angle B}{24} &= \frac{\sin \angle A}{21}\\\\ \frac{\cos \angle B + \cot \angle A \sin \angle B}{24} &= \frac{1}{21}\\\\ 21 \cos \angle B + 21 \cot \angle A \sin \angle B &= 24\tag{1}\end{align*}
