\begin{align*} 42 \cos \angle B \cos \angle A + 21 \cot \angle A \sin \angle B + 21 \cot \angle B \sin \angle A &= 48\\\\ 2 \cos \angle B \cos \angle A + \cot \angle A \sin \angle B + \cot \angle B \sin \angle A &= \frac{8}{7}\\\\ \cos \angle A \cos \angle B + \frac{1}{2} \sin (A + B) &= \frac{4}{7}\\\\ \cos \angle A \cos \angle B + \frac{1}{2} \sin (\angle C) &= \frac{4}{7}\\\\ \cos \angle A \cos \angle B + \frac{1}{2} \sin (\angle C) &= \frac{4}{7}\\\\ \cos \angle A \cos \angle B + \frac{1}{2} (24/28) &= \frac{4}{7}\\\\ \cos \angle A \cos \angle B &= \frac{1}{14}\tag{3}\end{align*}
